const job = $input.item.json || {};
const parseMaybeJson = (value) => {
  if (!value) return {};
  if (typeof value === 'object') return value;
  if (typeof value === 'string') {
    try {
      const parsed = JSON.parse(value);
      return parsed && typeof parsed === 'object' ? parsed : {};
    } catch {
      return {};
    }
  }
  return {};
};

const metadata = parseMaybeJson(job.metadata);
const profile = parseMaybeJson(job.user_profile);
const programPlan = parseMaybeJson(job.program_plan);
const weekMatch = String(job.template_key || '').match(/^week_(\d+)$/);
const weekNumber = Number(metadata.week_number || (weekMatch ? weekMatch[1] : 0)) || null;

const sessions = ['morning', 'midday', 'afternoon', 'evening'];
const pickImageUrl = (exercise = {}) => exercise.image_url || exercise.imageUrl || exercise.image || exercise.photo_url || exercise.photoUrl || '';
const mapExercise = (exercise) => exercise ? ({
  name: exercise.name,
  description: exercise.description,
  image_url: pickImageUrl(exercise),
  cues: exercise.cues
}) : null;

const weekPlanRaw = weekNumber ? (programPlan[`week_${weekNumber}`] || {}) : {};
const weekPlan = {};
for (const s of sessions) {
  const slot = weekPlanRaw[s] || {};
  weekPlan[s] = {
    warmup: mapExercise(slot.warmup),
    main: mapExercise(slot.main)
  };
}

const calendarMap = {
  1: $env.CALENDAR_WEEK1_URL || '',
  2: $env.CALENDAR_WEEK2_URL || '',
  3: $env.CALENDAR_WEEK3_URL || '',
  4: $env.CALENDAR_WEEK4_URL || ''
};
const calendarUrl = weekNumber ? (calendarMap[weekNumber] || $env.CALENDAR_DEFAULT_URL || '') : ($env.CALENDAR_DEFAULT_URL || '');

const txnId = String(job.paddle_transaction_id || '');
const checkoutFromLead = String(job.checkout_url || '').trim();
const paddleBase = String($env.PADDLE_API_URL || '').includes('sandbox') ? 'https://sandbox-buy.paddle.com' : 'https://buy.paddle.com';
const checkoutUrl = checkoutFromLead || (txnId ? `${paddleBase}/checkout/${txnId}` : '');

const fill = (str, vars) => String(str || '').replace(/{{\s*([a-zA-Z0-9_]+)\s*}}/g, (_, key) => String(vars[key] ?? ''));
const safeName = String(job.name || 'there');
const goal = profile.primary_goal || profile.goal || '';
const vars = {
  name: safeName,
  Name: safeName,
  goal,
  week_number: weekNumber || '',
  calendar_url: calendarUrl,
  week_pdf_url: '',
  level2_offer_url: $env.LEVEL2_OFFER_URL || '',
  feedback_url: $env.FEEDBACK_FORM_URL || '',
  checkout_url: checkoutUrl,
  mdt_blog_url: $env.MDT_BLOG_URL || ''
};

const requiresPdf = String(job.sequence_key || '') === 'no_payment_bounce'
  ? false
  : Boolean(job.requires_pdf || String(job.template_key || '').startsWith('week_') || metadata.requires_pdf === true);

const isPaid = String(job.lead_status || '').toLowerCase() === 'paid' || Boolean(job.payment_date);

return {
  json: {
    job_id: Number(job.job_id),
    lead_id: Number(job.lead_id),
    sequence_key: String(job.sequence_key || ''),
    template_key: String(job.template_key || ''),
    email: String(job.email || ''),
    name: safeName,
    week_number: weekNumber,
    requires_pdf: requiresPdf,
    is_paid: isPaid,
    profile,
    week_plan: weekPlan,
    calendar_url: calendarUrl,
    checkout_url: checkoutUrl,
    email_subject: fill(job.template_subject, vars),
    email_html: fill(job.template_html, vars),
    attachment_filename: weekNumber ? `week${weekNumber}-plan.pdf` : 'mdt-plan.pdf'
  }
};

const item = $input.item.json || {};
const shouldSkip = item.sequence_key === 'no_payment_bounce' && item.is_paid === true;
return { json: { ...item, should_skip: shouldSkip } };

const payload = $('Build Job Payload').item.json;
const response = $input.item.json || {};
const statusCode = Number(response.statusCode || response.code || 0);
const hasError = Boolean(response.error) || (statusCode >= 400 && statusCode !== 0);
const sendOk = !hasError;
const errorText = hasError ? String(response.error?.message || response.message || JSON.stringify(response.error || response).slice(0, 1000)) : '';

return {
  json: {
    job_id: payload.job_id,
    send_ok: sendOk,
    error_text: errorText
  }
};

const payload = $('Build Job Payload').item.json;
const pdfError = $input.item.json?.error || $input.item.json || {};
const message = String(pdfError.message || pdfError.description || JSON.stringify(pdfError).slice(0, 1000));
return { json: { job_id: payload.job_id, send_ok: false, error_text: `PDF generation failed: ${message}` } };
